<?php
 namespace WPAICG\Core\Providers\OpenAI\Methods; if (!defined('ABSPATH')) { exit; } function format_embeddings_logic_for_payload_formatter($input, array $options): array { $payload = [ 'input' => $input, 'model' => $options['model'] ?? 'text-embedding-3-small', ]; if (isset($options['dimensions']) && is_int($options['dimensions']) && $options['dimensions'] > 0) { $payload['dimensions'] = $options['dimensions']; } if (isset($options['encoding_format']) && in_array($options['encoding_format'], ['float', 'base64'])) { $payload['encoding_format'] = $options['encoding_format']; } if (isset($options['user']) && is_string($options['user'])) { $payload['user'] = $options['user']; } return $payload; }